function buildIndexPhases(
  config: IndexerConfig,
  options: IndexFilesOptions,
  speckitScanStart: number,
  scanOutcomeRef: { value: 'success' | 'error' },
): Phase[] {
  const skipFreshFiles = options.skipFreshFiles ?? true;
  const moduleResolver = getConfiguredModuleResolver(config);

  const findCandidates: Phase<Record<string, unknown>, FindCandidatesOutput> = {
    name: 'find-candidates',
    inputs: [],
    run() {
      if (options.specificFiles && options.specificFiles.length > 0) {
        const candidateFiles = collectSpecificFiles(
          config,
          options.specificFiles,
        );
        console.error(`[structural-indexer] refreshed ${candidateFiles.length} specific file(s)`);
        return {
          candidateFiles,
          warnings: [],
          capExceeded: { maxNodes: false, depth: false, gitignoreSize: false },
        };
      }

      const allFiles = new Set<string>();
      let excludedByDefault = 0;
      let excludedByGitignore = 0;
      const warnings: string[] = [];
      const capExceeded = { maxNodes: false, depth: false, gitignoreSize: false };

      for (const pattern of config.includeGlobs) {
        const found = findFiles(config, pattern);
        excludedByDefault += found.excludedByDefault;
        excludedByGitignore += found.excludedByGitignore;
        warnings.push(...found.warnings);
        capExceeded.maxNodes = capExceeded.maxNodes || found.capExceeded.maxNodes;
        capExceeded.depth = capExceeded.depth || found.capExceeded.depth;
        capExceeded.gitignoreSize = capExceeded.gitignoreSize || found.capExceeded.gitignoreSize;
        found.files.forEach(f => allFiles.add(f));
      }

      console.error(`[structural-indexer] scanned ${allFiles.size} files (excluded: gitignored=${excludedByGitignore}, default=${excludedByDefault})`);
      return { candidateFiles: [...allFiles], warnings, capExceeded };
    },
  };

  const parseCandidates: Phase<{ 'find-candidates': FindCandidatesOutput }, ParseCandidatesOutput> = {
    name: 'parse-candidates',
    inputs: ['find-candidates'],
    async run(deps) {
      const { candidateFiles, warnings, capExceeded } = deps['find-candidates'];
      const results: ParseResult[] = [];
      let preParseSkippedCount = 0;
      let unsupportedLanguageSkipped = 0;

      for (const file of candidateFiles) {
        // Cooperative cancellation runs inside the parse phase. runPhases only
        // checks the deadline signal BETWEEN phases, so a large parse-candidates loop would
        // otherwise run to completion after the caller's deadline aborts and discard the result.
        // Check per file so a timeout stops the parse promptly (one-file granularity).
        if (options.signal?.aborted) {
          throw new Error(`parse-candidates aborted (deadline signal) after ${results.length} parsed`);
        }
        const language = detectLanguage(file);
        if (!language || !config.languages.includes(language)) {
          unsupportedLanguageSkipped++;
          continue;
        }

        // P1 perf: skip read+parse for files whose mtime matches the DB record.
        // isFileStale returns true when the file is absent from the DB or its
        // mtime has changed — only then do we pay the I/O + parse cost.
        if (skipFreshFiles && !isFileStale(file)) {
          preParseSkippedCount++;
          continue;
        }

        try {
          const content = readFileSync(file, 'utf-8');
          const result = await parseFile(file, content, language, config.edgeWeights);
          results.push(result);
        } catch { /* skip unreadable */ }
      }

      if (unsupportedLanguageSkipped > 0) {
        warnings.push(`[structural-indexer] Skipped ${unsupportedLanguageSkipped} candidate file(s) before parsing because their language is unsupported or disabled by config.languages`);
      }

      return { candidateFiles, results, preParseSkippedCount, unsupportedLanguageSkipped, warnings, capExceeded };
    },
  };

  const finalize: Phase<{ 'parse-candidates': ParseCandidatesOutput }, FinalizeOutput> = {
    name: 'finalize',
    inputs: ['parse-candidates'],
    run(deps) {
      const { results, preParseSkippedCount, unsupportedLanguageSkipped, warnings, capExceeded } = deps['parse-candidates'];
      const finalizedResults = finalizeIndexResults(results, moduleResolver, config.edgeWeights);
      return { finalizedResults, preParseSkippedCount, unsupportedLanguageSkipped, warnings, capExceeded };
    },
  };

